checkCliAvailable()
    .then((available) => {
      if (available) {
        output.appendLine("Archon CLI detected — extension ready.");
      } else {
        output.appendLine(
          "Archon CLI not found — will prompt on first use.",
        );
        // Show a subtle notification (not modal)
        vscode.window
          .showWarningMessage(
            "Archon CLI not found. Some features require the CLI.",
            "Install",
            "Set Path",
          )
          .then((choice) => {
            if (choice === "Install") {
              const terminal =
                vscode.window.createTerminal("Archon Install");
              terminal.sendText("pip install archon");
              terminal.show();
            } else if (choice === "Set Path") {
              vscode.commands.executeCommand(
                "workbench.action.openSettings",
                "archon.cliPath",
              );
            }
          });
      }
    })
    .catch

data.platforms
      .map((p) => {
        const statusColor =
          p.status === "healthy"
            ? "#22c55e"
            : p.status === "degraded"
              ? "#eab308"
              : p.status === "error"
                ? "#ef4444"
                : "#6b7280";
        const statusIcon =
          p.status === "healthy"
            ? "✓"
            : p.status === "degraded"
              ? "⚠"
              : p.status === "error"
                ? "✗"
                : "—";

        const checksHtml = p.checks
          .map((c) => {
            const chkColor =
              c.status === "pass"
                ? "#22c55e"
                : c.status === "warn"
                  ? "#eab308"
                  : "#ef4444";
            const chkIcon =
              c.status === "pass" ? "✓" : c.status === "warn" ? "⚠" : "✗";
            return `<div class="check-item">
                    <span style="color:${chkColor}">${chkIcon}</span>
                    <span>${this._esc(c.name)}: ${this._esc(c.message)}</span>
                    ${c.suggestion ? `<div class="suggestion">${this._esc(c.suggestion)}</div>` : ""}
                </div>`;
          })
          .join("");

        return `<div class="platform-card">
                <div class="platform-header">
                    <span class="platform-name">${this._esc(p.name)}</span>
                    <span class="platform-status" style="color:${statusColor}">${statusIcon} ${this._esc(p.status)}</span>
                </div>
                <div class="platform-msg">${this._esc(p.message)}</div>
                ${checksHtml ? `<div class="checks">${checksHtml}</div>` : ""}
            </div>`;
      })
      .join

